  1	import { type FC, type MouseEvent, type Ref, useCallback, useMemo, useState } from 'react';
  2	
  3	import {
  4	  MenuToggle,
  5	  type MenuToggleElement,
  6	  Select,
  7	  SelectList,
  8	  SelectOption,
  9	} from '@patternfly/react-core';
 10	
 11	/**
 12	 * @typedef Option
 13	 * @property {number} key
 14	 * @property {number | string} name
 15	 * @property {string} description
 16	 */
 17	type Option = {
 18	  key: number | string;
 19	  name: string;
 20	  description: string;
 21	};
 22	
 23	/**
 24	 * @typedef SettingsSelectInputProps
 25	 * @property {string} value - The current selected value
 26	 * @property {(value: string) => void} onChange - Function to call when the value changes
 27	 * @property {Option[]} options - The options to present to the user
 28	 */
 29	type SettingsSelectInputProps = {
 30	  value: number | string;
 31	  onChange: (value: number | string) => void;
 32	  options: Option[];
 33	};
 34	
 35	/**
 36	 * SelectInput component. Provides a select input form element with predefined options.
 37	 */
 38	const SettingsSelectInput: FC<SettingsSelectInputProps> = ({ onChange, options, value }) => {
 39	  // State to keep track of the dropdown menu open/closed state
 40	  const [isOpen, setIsOpen] = useState(false);
 41	
 42	  // Build a dictionary mapping option names to keys for efficient lookup
 43	  // This dictionary is re-calculated every time the options prop changes
 44	  const nameToKey = useMemo(() => {
 45	    return options?.reduce<Record<string, string | number>>((dict, option) => {
 46	      dict[option.name] = option.key;
 47	      return dict;
 48	    }, {});
 49	  }, [options]);
 50	
 51	  const keyToName = useMemo(() => {
 52	    return options?.reduce<Record<string, string | number>>((dict, option) => {
 53	      dict[option.key] = option.name;
 54	      return dict;
 55	    }, {});
 56	  }, [options]);
 57	
 58	  const valueLabel = keyToName?.[value] ?? value;
 59	  const [selected, setSelected] = useState<string | number>(valueLabel);
 60	
 61	  const onToggleClick = () => {
 62	    setIsOpen((open) => !open);
 63	  };
 64	
 65	  const toggle = (toggleRef: Ref<MenuToggleElement>) => (
 66	    <MenuToggle
 67	      ref={toggleRef}
 68	      onClick={onToggleClick}
 69	      isExpanded={isOpen}
 70	      className="forklift-overview__settings-select"
 71	    >
 72	      {selected || 'Select an option'}
 73	    </MenuToggle>
 74	  );
 75	
 76	  const renderOptions = () => {
 77	    return options?.map((option) => (
 78	      <SelectOption key={option.key} value={option.name} description={option.description}>
 79	        {option.name}
 80	      </SelectOption>
 81	    ));
 82	  };
 83	
 84	  // Callback function to handle selection in the dropdown menu
 85	  const onSelect = useCallback(
 86	    (_event?: MouseEvent, selectedValue?: string | number) => {
 87	      if (selectedValue === undefined) {
 88	        setIsOpen(false);
 89	        return;
 90	      }
 91	      // Use the dictionary to find the key corresponding to the selected name
 92	      const key = nameToKey[selectedValue] || selectedValue;
 93	      onChange(key);
 94	
 95	      // Toggle the dropdown menu open state
 96	      setSelected(selectedValue as string);
 97	      setIsOpen(false);
 98	    },
 99	    [nameToKey, onChange],
100	  );
101	
102	  // Render the Select component with dynamically created SelectOption children
103	  return (
104	    // Custom select does not support the complex toggle being used here
105	    // eslint-disable-next-line no-restricted-syntax
106	    <Select
107	      role="menu"
108	      aria-label="Select Input with descriptions"
109	      aria-labelledby="exampleSelect"
110	      isOpen={isOpen}
111	      selected={selected}
112	      onSelect={onSelect}
113	      onOpenChange={(nextOpen: boolean) => {
114	        setIsOpen(nextOpen);
115	      }}
116	      toggle={toggle}
117	      shouldFocusToggleOnSelect
118	      shouldFocusFirstItemOnOpen={false}
119	      popperProps={{
120	        direction: 'down',
121	        enableFlip: true,
122	      }}
123	    >
124	      <SelectList>{renderOptions()}</SelectList>
125	    </Select>
126	  );
127	};
128	
129	export default SettingsSelectInput;

